import assert from 'assert'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

function makeHeaders(entries: Record<string, string>): Headers {
  const h = new Headers()
  for (const [key, value] of Object.entries(entries)) {
    h.set(key, value)
  }
  return h
}

// geo() with Vercel headers
{
  const headers = makeHeaders({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })
  const result = geo({ headers })
  assert.strictEqual(result.city, 'San Francisco', 'city from Vercel header')
  assert.strictEqual(result.countryCode, 'US', 'countryCode from Vercel header')
  assert.strictEqual(result.country, 'United States', 'country name lookup')
  assert.strictEqual(result.region, 'CA', 'region from Vercel header')
  assert.strictEqual(result.latitude, '37.7749', 'latitude from Vercel header')
  assert.strictEqual(
    result.longitude,
    '-122.4194',
    'longitude from Vercel header'
  )
  assert.strictEqual(
    result.timezone,
    'America/Los_Angeles',
    'timezone from Vercel header'
  )
}

// geoFromHeaders() with Cloudflare fallback for countryCode
{
  const headers = makeHeaders({
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(
    result.countryCode,
    'DE',
    'countryCode from Cloudflare header'
  )
  assert.strictEqual(result.country, 'Germany', 'country name from Cloudflare')
  assert.strictEqual(result.city, undefined, 'city is undefined when missing')
}

// Vercel country header takes precedence over Cloudflare
{
  const headers = makeHeaders({
    'x-vercel-ip-country': 'FR',
    'cf-ipcountry': 'DE',
  })
  const result = geoFromHeaders(headers)
  assert.strictEqual(
    result.countryCode,
    'FR',
    'Vercel header takes precedence over Cloudflare'
  )
  assert.strictEqual(result.country, 'France', 'correct country name')
}

// isInRegion() matching
{
  const g = { countryCode: 'US' }
  assert.strictEqual(
    isInRegion(g, ['US', 'CA', 'MX']),
    true,
    'matches when countryCode in list'
  )
  assert.strictEqual(
    isInRegion(g, ['us', 'ca']),
    true,
    'case-insensitive match'
  )
}

// isInRegion() non-matching
{
  const g = { countryCode: 'GB' }
  assert.strictEqual(
    isInRegion(g, ['US', 'CA']),
    false,
    'no match when countryCode not in list'
  )
}

// isInRegion() with undefined countryCode
{
  const g = {}
  assert.strictEqual(
    isInRegion(g, ['US']),
    false,
    'returns false when countryCode is undefined'
  )
}

// geoDistance() New York to London ~5570 km (allow ±50 km)
{
  // New York: 40.7128° N, 74.0060° W
  // London:   51.5074° N,  0.1278° W
  const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(dist - 5570) <= 50,
    `NY-to-London distance ${dist.toFixed(1)} km should be ~5570 km`
  )
}

// geoDistance() same point => 0
{
  const dist = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
  assert.strictEqual(dist, 0, 'distance from a point to itself is 0')
}

// Missing headers return undefined fields
{
  const headers = makeHeaders({})
  const result = geoFromHeaders(headers)
  assert.strictEqual(result.city, undefined, 'city undefined when no headers')
  assert.strictEqual(
    result.countryCode,
    undefined,
    'countryCode undefined when no headers'
  )
  assert.strictEqual(
    result.country,
    undefined,
    'country undefined when no headers'
  )
  assert.strictEqual(
    result.region,
    undefined,
    'region undefined when no headers'
  )
  assert.strictEqual(
    result.latitude,
    undefined,
    'latitude undefined when no headers'
  )
  assert.strictEqual(
    result.longitude,
    undefined,
    'longitude undefined when no headers'
  )
  assert.strictEqual(
    result.timezone,
    undefined,
    'timezone undefined when no headers'
  )
}

// Country name lookup for all 10 common codes
{
  const cases: [string, string][] = [
    ['AU', 'Australia'],
    ['BR', 'Brazil'],
    ['CA', 'Canada'],
    ['CN', 'China'],
    ['DE', 'Germany'],
    ['FR', 'France'],
    ['GB', 'United Kingdom'],
    ['IN', 'India'],
    ['JP', 'Japan'],
    ['US', 'United States'],
  ]
  for (const [code, name] of cases) {
    const result = geoFromHeaders(makeHeaders({ 'x-vercel-ip-country': code }))
    assert.strictEqual(
      result.country,
      name,
      `country name for ${code} should be "${name}"`
    )
  }
}

// Unknown country code returns undefined country name
{
  const result = geoFromHeaders(
    makeHeaders({ 'x-vercel-ip-country': 'ZZ' })
  )
  assert.strictEqual(result.countryCode, 'ZZ', 'unknown countryCode is kept')
  assert.strictEqual(
    result.country,
    undefined,
    'unknown countryCode yields undefined country name'
  )
}

console.log('All geo tests passed.')

